var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이걸로 끝이야───!!","JPN":"これで終わりだ───！！","ENG":"It's all over now!!","TWN":"到此為止了────！！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!!","JPN":"はあ、はあ、はあ……！！","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이거 CRF 소모가 장난이 아니잖아……?","JPN":"これ、CRFをめちゃくちゃ消耗するな……","ENG":"This really consumes a lot of CRF...","TWN":"CRF消耗得也太厲害了吧……？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 메인 드라이브에 치명적인 손상 발생.</color>","JPN":"<color=#ff3636>警告。メインドライブに致命的な損傷発生。</color>","ENG":"<color=#ff3636>Warning. Critical damage to the main drive.</color>","TWN":"<color=#ff3636>警告。主引擎遭到致命損壞。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>함의 기능 저하 확인. 자가 수리 모드 활성화.</color>","JPN":"<color=#ff3636>艦の機能低下確認。自己修理モード活性化。</color>","ENG":"<color=#ff3636>Ship's function degradation confirmed. Activating self-repair mode.</color>","TWN":"<color=#ff3636>檢測到艦船機能下降。自我修復模式啟動。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 상정되지 않은 출력 확인.</color>","JPN":"<color=#ff3636>警告。想定外の出力確認。</color>","ENG":"<color=#ff3636>Warning. Unexpected output confirmed.</color>","TWN":"<color=#ff3636>警告。檢測到非預期輸出。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>인간. 연합의 기술을 사용하고 있군요.</color>","JPN":"<color=#ff3636>人間。連合の技術を使用していますね。</color>","ENG":"<color=#ff3636>Human. You are using Interstellar Alliance technology.</color>","TWN":"<color=#ff3636>人類。你正在使用聯盟技術。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"연합……?","JPN":"連合……？","ENG":"Interstellar...?","TWN":"聯盟……？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"하하, 지금까지 자동응답기인 줄 알았는데, 말이 통하는 녀석이었나 보네……?","JPN":"はは、自動応答システムだと思ってたのに、言葉が通じるやつだったようだな……？","ENG":"Haha, I just assumed you were a recording, but it seems that you can talk, eh...?","TWN":"哈哈，我之前一直以為是個自動回覆的機器，看來是可以和我交流的……？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"왜? 깡통 주제에 너희 기술력에 자부심이라도 느끼나 봐……?","JPN":"何だ？　ボロ缶のくせに、自分たちの技術力にプライドでも感じてるのか……？","ENG":"What? Do tin buckets also feel pride in their technology...?","TWN":"為什麼？你一個廢鐵，似乎對自己的技術十分自有信……？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"큭큭, 근데 어쩌냐……?","JPN":"ククッ、でも残念だな……","ENG":"Haha, but what can you do...?","TWN":"呵呵，不過又能怎麼樣呢……？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"너네 기술 우리 잘난 꼬맹이가 다 털어버렸는데?","JPN":"おまえらのその技術、うちの偉いちんちくりんが全部盗ってやったよ。","ENG":"Our genius has already stolen your high-tech!","TWN":"你們的技術已經被我們了不起的小鬼偷走了。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>의문. 당신은 이상합니다. 정상 범주에 벗어납니다.</color>","JPN":"<color=#ff3636>疑問。あなたはおかしいです。正常の範囲から外れています。</color>","ENG":"<color=#ff3636>Question. You are strange. Beyond normal range.</color>","TWN":"<color=#ff3636>提問。你很奇怪。超出了正常範圍。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>인간의 육체로 아베스타 드라이브의 출력을 견딜 가능성 전무.</color>","JPN":"<color=#ff3636>人間の肉体でアヴェスター・ドライブの出力に耐えられる可能性は皆無。</color>","ENG":"<color=#ff3636>There is no possibility that a human body can withstand the output of Avesta Drive.</color>","TWN":"<color=#ff3636>人類的身體不可能承受得住阿貝斯塔引擎的輸出。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>침식파에 노출되면 인간은 침식체가 됩니다.</color>","JPN":"<color=#ff3636>侵食波に触れると普通、人間は侵食体になります。</color>","ENG":"<color=#ff3636>Humans exposed to Corruption rays turn into C.O.s.</color>","TWN":"<color=#ff3636>當暴露在侵蝕波中時，人類將會變成侵蝕體。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>인간. 당신은 침식체가 되고 싶습니까?</color>","JPN":"<color=#ff3636>人間。あなたは侵食体になりたいのですか？</color>","ENG":"<color=#ff3636>Human. Do you wish to become a C.O.?</color>","TWN":"<color=#ff3636>人類。你想成為侵蝕體嗎？</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"닥쳐! 그럴 리가 없잖아!","JPN":"黙れ！　そんなわけないだろう！","ENG":"Shut up! Why would I want that?!","TWN":"閉嘴！怎麼可能！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"난 단지 내 전대원들을 지키고 싶을 뿐이라고!!","JPN":"アタシはただ、アタシの戦隊員たちを守りたいだけだ！！","ENG":"All I want is to protect my division members!","TWN":"我只是想保護我的戰隊員！！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"너희가 그걸 방해하니까 여기까지 찾아온 거야.","JPN":"それをおまえらが邪魔するからここまで来たんだよ。","ENG":"And you're interfering with that! That's why I'm here!","TWN":"就是因為你的阻礙，我才千里迢迢來到這裡。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"애초에 너희야말로 왜 이딴 짓거리를 저지르는 건데?","JPN":"そもそもおまえらこそなんでこんなことしてるんだ？","ENG":"Why would you do something like this in the first place, huh?","TWN":"反倒是我想問你，你們為什麼要做這樣的事情？！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>응답. 엄정하신 아시모프의 이름 아래.</color>","JPN":"<color=#ff3636>応答。厳正なるアシモフの名の下で。</color>","ENG":"<color=#ff3636>Answer. Under the impartial name of Asimov.</color>","TWN":"<color=#ff3636>回答。冠以阿西莫夫之名。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>우리 연합은 인간을 시험해야 할 의무가 있습니다.</color>","JPN":"<color=#ff3636>我々連合は、人間を試す義務があります。</color>","ENG":"<color=#ff3636>The Interstellar Alliance has a duty to test humanity.</color>","TWN":"<color=#ff3636>聯盟有義務考驗人類。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>선단에 탑승할 인류를 선별하기 위해서.</color>","JPN":"<color=#ff3636>船団に搭乗する人類を選別するために。</color>","ENG":"<color=#ff3636>To select humans to board the fleet.</color>","TWN":"<color=#ff3636>篩選人類登上船隊。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"선별한다고……?","JPN":"選別する……？","ENG":"Select...?","TWN":"篩選……？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그게 무슨 헛소리야!!","JPN":"何を戯けたことを！！","ENG":"What's that supposed to mean?!","TWN":"這是什麼鬼話！！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>전제 하나. 이 세계는 멸망을 피할 수 없습니다.</color>","JPN":"<color=#ff3636>前提一。この世界は滅亡を避けられません。</color>","ENG":"<color=#ff3636>First premise. This world will meet is inevitable end.</color>","TWN":"<color=#ff3636>前提一。這個世界無法避免被毀滅。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};